### 2. JPA Entity 설계 제안

파일 위치: `domain/src/main/kotlin/com/maum/backend/entity/`

```kotlin
// entity/user/UserEntity.kt
@Entity
@Table(catalog = "maum", name = "user")
class UserEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    val nickname: String,
    val gender: Int,           // 0: MALE, 1: FEMALE
    val birthYear: Int,
    var mannerScore: Float = 3.0f,
    var isVerified: Boolean = false,

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),
)

// entity/call/CallEntity.kt
@Entity
@Table(catalog = "maum", name = "call")
class CallEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    val callerId: String,
    val calleeId: String,
    var status: Int = 0,       // 0:PENDING, 1:ONGOING, 2:ENDED, 3:MISSED, 4:DECLINED
    var durationSeconds: Int? = null,
    var startedAt: LocalDateTime? = null,
    var endedAt: LocalDateTime? = null,

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),
)

// entity/follow/FollowEntity.kt
@Entity
@Table(catalog = "maum", name = "follow")
class FollowEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    val followerId: String,
    val followeeId: String,

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),
)

// entity/moment/MomentEntity.kt  (catalog = "moment")
@Entity
@Table(catalog = "moment", name = "moment")
class MomentEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    val authorId: String,
    val content: String,
    var likeCount: Int = 0,
    var commentCount: Int = 0,

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),
)
```

